const crypto = require('crypto');
const BOT_TOKEN = '6939723174:AAE59AdG4oigMzBmWQQmxbUiidm562T_Fnc';
const body = $input.first().json.body || $input.first().json;
const initDataRaw = body.init_data || '';

function sha256(data) {
  return crypto.createHash('sha256').update(data).digest();
}

let authValid = false;
try {
  if (initDataRaw) {
    const params = new URLSearchParams(initDataRaw);
    const hash = params.get('hash');
    params.delete('hash');
    const pairs = [];
    params.forEach((v, k) => pairs.push(`${k}=${v}`));
    pairs.sort();
    const checkString = pairs.join('\n');
    const secret = crypto.createHmac('sha256', sha256('WebAppData')).update(BOT_TOKEN).digest();
    const computed = crypto.createHmac('sha256', secret).update(checkString).digest('hex');
    authValid = computed === hash;
    // Check auth_date freshness (24h)
    const authDate = parseInt(params.get('auth_date') || '0', 10);
    if (authValid && authDate > 0) {
      const now = Math.floor(Date.now() / 1000);
      if (now - authDate > 86400) authValid = false;
    }
  }
} catch (e) {
  authValid = false;
}

return [{ json: { ...body, _auth_valid: authValid } }];

const body = $('Webhook').first().json.body;

// --- Photo 1 (required) ---
const base64 = body.photo_base64;
const mime = body.mime_type || 'image/jpeg';
const ext = mime.includes('png') ? 'png' : 'jpg';
const ts = Date.now();
const rand = Math.random().toString(36).slice(2, 8);
const filename = `photosession/${ts}_${rand}.${ext}`;
const buf = Buffer.from(base64, 'base64');

const result = {
  s3_filename: filename,
  s3_url: `https://s3.timeweb.cloud/cf384f43-avatar-bot-generations/${filename}`,
  user_id: body.user_id,
  theme: body.theme,
  mime_type: mime,
};

const items = [{
  json: { ...result, photo_index: 1, has_photo2: !!body.photo2_base64 },
  binary: {
    data: {
      data: buf.toString('base64'),
      mimeType: mime,
      fileName: filename,
    }
  }
}];

// --- Photo 2 (optional) ---
if (body.photo2_base64) {
  const mime2 = body.photo2_mime_type || 'image/jpeg';
  const ext2 = mime2.includes('png') ? 'png' : 'jpg';
  const rand2 = Math.random().toString(36).slice(2, 8);
  const filename2 = `photosession/${ts}_${rand2}_ref.${ext2}`;
  const buf2 = Buffer.from(body.photo2_base64, 'base64');

  items.push({
    json: {
      s3_filename: filename2,
      s3_url: `https://s3.timeweb.cloud/cf384f43-avatar-bot-generations/${filename2}`,
      user_id: body.user_id,
      theme: body.theme,
      mime_type: mime2,
      photo_index: 2,
      has_photo2: true,
    },
    binary: {
      data: {
        data: buf2.toString('base64'),
        mimeType: mime2,
        fileName: filename2,
      }
    }
  });
}

return items;

